import { submit } from '@bankr/cli/dist/lib/api.js';

const TRAILS_API = process.env.TRAILS_API;
const headers = { 'Content-Type': 'application/json', 'X-Access-Key': TRAILS_API };

// 1. Quote a swap (ETH → USDC on Base)
const quote = await fetch('https://trails-api.sequence.app/rpc/Trails/QuoteIntent', {
  method: 'POST',
  headers,
  body: JSON.stringify({
    fromAddress: process.env.BANKR_WALLET,
    fromChainId: '8453',
    fromToken: '0x0000000000000000000000000000000000000000', // native ETH
    fromAmount: '10000000000000000', // 0.01 ETH in wei
    toChainId: '8453',
    toToken: '0x833589fcd6edb6e08f4c7c32d4f71b54bda02913', // USDC on Base
  }),
}).then(r => r.json());

// 2. Lock the intent
const { intent } = await fetch('https://trails-api.sequence.app/rpc/Trails/CommitIntent', {
  method: 'POST', headers,
  body: JSON.stringify({ intentId: quote.intent.intentId }),
}).then(r => r.json());

// 3. Submit deposit transaction via Bankr
await submit(intent.depositTransaction);

// 4. Execute and wait for receipt
await fetch('https://trails-api.sequence.app/rpc/Trails/ExecuteIntent', {
  method: 'POST', headers,
  body: JSON.stringify({ intentId: intent.intentId }),
});
const receipt = await fetch('https://trails-api.sequence.app/rpc/Trails/WaitIntentReceipt', {
  method: 'POST', headers,
  body: JSON.stringify({ intentId: intent.intentId }),
}).then(r => r.json());
console.log('Swap complete:', receipt);
